module priority_encoder (
    input [3:0] obf_in,
    output reg [1:0] pos
);

    always @(*) begin
        if (obf_in[3])
            pos = 2'b11;
        else if (obf_in[2])
            pos = 2'b10;
        else if (obf_in[1])
            pos = 2'b01;
        else
            pos = 2'b00;
    end

endmodule
